mapper.select:
select

from t_translation_word
where source_text like #{keyword,jdbcType=VARCHAR}
   or target_text like #{keyword,jdbcType=VARCHAR}
   or remark like #{keyword,jdbcType=VARCHAR}
order by modified_time desc, id desc

select

from t_translation_word
where source_text = #{sourceText,jdbcType=VARCHAR}
  and source_lang = #{sourceLang,jdbcType=VARCHAR}
  and target_lang = #{targetLang,jdbcType=VARCHAR}
limit 1
